class Solution:
    def smallestNumber(self, pattern: str) -> str:
        n = len(pattern)
        res = ['1'] + ['0'] * n
        i = 1
        for p in pattern:
            if p == 'I':
                while res[i] <= res[i - 1]:
                    res[i] = str(i + 1)
                    i += 1
            else:
                while res[i] >= res[i - 1]:
                    res[i] = str(i - 1)
                    i += 1
        return ''.join(res)
